/* ================= CLEAN MAIN REFERENCE DESIGN ================= */
.cpd-dashboard{
  --page:#040b13;
  --panel:#071522;
  --panel-raised:#0a1b2b;
  --panel-head:#0b1d2e;
  --line:#22577d;
  --line-soft:#163a55;
  --text:#f4f7fb;
  --muted:#adbed1;
  --cyan:#36aef8;
  --green:#39d353;
  --red:#ff5a5f;
  --amber:#e8a62b;
  --grey:#8995a4;
  width:100%;height:100%;min-height:0;margin:0;padding:6px 8px;
  box-sizing:border-box;overflow:hidden;
  display:grid;grid-template-rows:52px minmax(0,1fr) 36px;gap:8px;
  color:var(--text);font-family:"Segoe UI Variable Text","Segoe UI",system-ui,sans-serif;
  font-size:15px;font-variant-numeric:tabular-nums lining-nums;
  background:linear-gradient(rgba(54,174,248,.018) 1px,transparent 1px),linear-gradient(90deg,rgba(54,174,248,.018) 1px,transparent 1px),var(--page);
  background-size:40px 40px,40px 40px,auto;
}
.cpd-dashboard *{box-sizing:border-box;min-width:0;}
.cpd-dashboard a{text-decoration:none;}
.cpd-header{
  height:52px;padding:0 18px;display:flex;align-items:center;justify-content:space-between;
  border:1px solid var(--line);border-radius:8px;background:linear-gradient(90deg,#06111d,#081827);
}
.cpd-title{color:#fff;font-size:22px;font-weight:800;letter-spacing:.015em;}
.cpd-subtitle{padding:8px 14px;border:1px solid var(--line);border-radius:7px;background:#0a1d2d;color:#dff2ff;font-size:15px;font-weight:700;white-space:nowrap;}
.summary-kpi-card{
  position:relative;overflow:hidden;padding:13px 16px 14px;
  display:grid;grid-template-rows:auto 1fr 4px;align-items:center;
  border:1px solid var(--line);border-radius:7px;background:linear-gradient(180deg,#091a2a,#06121e);
}
.summary-kpi-card .kpi-label{color:#e7eef8;font-size:15px;font-weight:750;letter-spacing:.01em;white-space:nowrap;}
.summary-kpi-card .kpi-value{padding:0;border:0;background:none;box-shadow:none;font-size:34px;line-height:1;font-weight:800;}
.kpi-value-line{align-self:center;display:flex;align-items:baseline;justify-content:center;gap:8px;}
.kpi-unit{color:#c8d5e5;font-size:16px;font-weight:700;line-height:1;}
.summary-kpi-card .kpi-track{height:4px;border-radius:4px;background:#283646;}
.summary-kpi-card .kpi-track::after{content:"";display:block;width:70%;height:100%;border-radius:inherit;background:var(--green);}
.summary-available .kpi-track::after{background:var(--cyan);}
.summary-kpi-card .kpi-green{color:var(--green)!important;}
.summary-kpi-card .kpi-grey{color:var(--cyan)!important;}
.cpd-main-grid{height:100%;min-height:0;display:grid;grid-template-columns:minmax(0,57fr) minmax(0,43fr);gap:8px;overflow:hidden;}
.cpd-col-left,.cpd-col-right{min-height:0;display:grid;gap:8px;overflow:hidden;}
.cpd-col-left{grid-template-rows:minmax(0,43fr) minmax(0,34fr) minmax(0,23fr);}
.cpd-col-right{grid-template-rows:190px 240px minmax(200px,1fr);}
.cpd-card,.aux-systems-card{
  min-height:0;margin:0;padding:0;overflow:hidden;
  border:1px solid var(--line);border-radius:7px;background:linear-gradient(180deg,var(--panel-raised),var(--panel));box-shadow:none;
}
.cpd-card{display:flex;flex-direction:column;}
.cpd-card-header,.aux-systems-title{
  flex:0 0 38px;height:38px;padding:0 14px;display:flex;align-items:center;
  border-bottom:1px solid var(--line-soft);background:var(--panel-head);color:#f5f8fc;
  font-size:17px;font-weight:750;letter-spacing:.01em;
}
.cpd-card-body{flex:1 1 auto;min-height:0;padding:8px 10px;overflow:hidden;}
.bulk-layout{display:grid!important;grid-template-rows:minmax(0,1fr);gap:0;}
.tank-grid{width:100%;height:100%;display:grid;align-items:center;justify-items:center;align-content:space-evenly;}
#bulkGrid{grid-template-columns:repeat(10,minmax(0,1fr));grid-template-rows:repeat(4,minmax(0,1fr));gap:6px 8px;}
#bulkGrid .tank-circle{width:96px;min-width:96px;font-size:20px;}
.tank-circle{
  display:flex;align-items:center;justify-content:center;text-align:center;
  width:80px;height:68px;min-width:80px;min-height:68px;padding:4px;
  border:1px solid;border-radius:5px;color:#fff;font-size:20px;line-height:1.02;font-weight:750;
  background:#15202c;border-color:#6f7d8c;
}
.tank-circle.green{background:linear-gradient(180deg,#123d22,#0b2b19);border-color:#239c42;color:#effff2;}
.tank-circle.red{background:linear-gradient(180deg,#542124,#311417);border-color:#e44a4f;color:#fff2f2;}
.tank-circle.grey{background:linear-gradient(180deg,#46515e,#2e3742);border-color:#8995a4;color:#f1f4f8;}
.tank-circle[href]{cursor:pointer;}
.tank-circle[href]:hover{border-color:#7bd0ff;box-shadow:0 0 0 1px rgba(54,174,248,.25);}
.tank-circle[href]:focus-visible,.caa-tank[href]:focus-visible{outline:2px solid #7bd0ff;outline-offset:2px;}
.main-status-footer{display:flex;align-items:center;gap:18px;color:#c8d5e5;font-size:13px;font-weight:600;}
.main-status-footer span{display:flex;align-items:center;gap:6px;white-space:nowrap;}
.legend-swatch{width:14px;height:14px;display:inline-block;border:1px solid;border-radius:3px;}
.state-green{border-color:#239c42;background:#0b3c1d}.state-cyan{border-color:#36aef8;background:#0b2940}.state-grey{border-color:#8995a4;background:#39434f}.state-amber{border-color:#d99a22;background:#6a4b15}.state-red{border-color:#e44a4f;background:#662127}
.mixing-layout{display:grid!important;grid-template-columns:62px minmax(0,1fr);gap:8px;}
.mixing-row-labels{display:grid;grid-template-rows:repeat(3,minmax(0,1fr));gap:7px;}
.mixing-row-labels span{display:flex;align-items:center;justify-content:center;border:1px solid #2e86bd;border-radius:5px;background:#0a2940;color:#d6efff;font-size:16px;font-weight:750;}
#mixingGrid{grid-template-columns:repeat(12,minmax(0,1fr));grid-template-rows:repeat(3,minmax(0,1fr));gap:2px;}
#mixingGrid .tank-circle{width:80px;height:62px;min-width:80px;min-height:62px;font-size:20px;}
.cpd-bottom-grid{min-height:0;display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px;overflow:hidden;}
.cpd-bottom-grid .cpd-card{width:100%;min-height:0;}
#coagulantGrid{grid-template-columns:repeat(5,minmax(0,1fr));gap:6px;}
#coagulantGrid .tank-circle{width:80px;height:64px;min-width:80px;min-height:64px;font-size:20px;}
.caa-body{padding:9px;}
.caa-grid{width:100%;height:100%;display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:8px;}
.caa-unit-card{min-height:0;display:grid;grid-template-rows:38px minmax(0,1fr);overflow:hidden;border:1px solid #268640;border-radius:6px;background:#081b14;}
.caa-tank{display:flex;align-items:center;justify-content:center;border:0;border-bottom:1px solid rgba(57,211,83,.28);background:#0b2a1a;color:#6bea80;font-size:16px;font-weight:750;}
.caa-supply{min-height:0;padding:10px 12px;display:flex;flex-direction:column;justify-content:center;gap:8px;background:transparent!important;border:0!important;}
.caa-row{display:flex;align-items:center;justify-content:space-between;gap:8px;}
.caa-label{color:#b8c6d6;font-size:13px;font-weight:700;}
.caa-value{color:#f4f8fb;font-size:18px;font-weight:800;text-align:right;}
.caa-unit-card:has(.caa-green),.caa-panel-green{border-color:#269d45;}
.caa-green{background:#0c351f;color:#71ef87;}
.caa-grey{background:#27313c;color:#dbe2ea;border-color:#778492;}
.caa-unit-card:has(.caa-grey){border-color:#687786;background:#121b25;}
.caa-panel-grey .caa-label{color:#bcc6d0}.caa-panel-grey .caa-value{color:#eef2f6}
.aux-systems-card{display:grid;grid-template-rows:38px minmax(0,1fr);}
.aux-systems-body{min-height:0;padding:7px 9px;display:flex;flex-direction:column;gap:6px;}
.aux-systems-body>.cpd-card{flex:1 1 0;display:grid;grid-template-columns:100px minmax(0,1fr);grid-template-rows:1fr;border-color:#194966;border-radius:5px;background:#07131f;}
.aux-systems-body .cpd-card-header{width:auto;height:auto;min-height:0;padding:0 10px;border:0;border-right:1px solid #194966;background:#091827;font-size:14px;white-space:normal;}
.aux-systems-body .cpd-card-body{width:100%;height:auto;min-height:0;padding:4px 8px;display:flex;align-items:center;overflow:hidden;}
#polymerGrid,#coatingGrid,#storageGrid{width:100%;height:100%;margin:0;padding:0;display:flex;align-items:center;justify-content:flex-start;gap:4px;overflow:hidden;}
#polymerGrid .tank-circle,#coatingGrid .tank-circle,#storageGrid .tank-circle{width:48px;height:48px;min-width:48px;min-height:48px;border-radius:6px;font-size:16px;}
#cdsGrid{width:100%;height:100%;display:grid;grid-template-columns:repeat(6,minmax(0,1fr));grid-auto-rows:minmax(0,1fr);align-items:center;justify-items:center;gap:6px 8px;}
#cdsGrid .tank-circle{width:64px;height:48px;min-width:64px;min-height:48px;border-radius:6px;font-size:16px;}
.cds-kpi-column{display:none;}
.cpd-card[hidden]{display:none!important;}
.alarm-card{min-height:0;}
.alarm-card .cpd-card-header{justify-content:space-between;gap:12px;}
.alarm-count{height:28px;padding:0 8px;display:flex;align-items:center;gap:8px;border:1px solid #355c7d;border-radius:7px;background:#111e2d;color:#dce9f8;white-space:nowrap;}
.alarm-count span{font-size:12px;font-weight:700;letter-spacing:.04em;}
.alarm-count strong{min-width:20px;color:#fff;font-size:20px;line-height:1;font-weight:800;text-align:right;}
.alarm-body{flex:1 1 auto;min-height:0;padding:7px 9px;display:grid;grid-template-rows:30px minmax(0,1fr);gap:6px;overflow:hidden;}
.alarm-list-head,.alarm-row{display:grid;grid-template-columns:.75fr .85fr 2fr .8fr .9fr;align-items:center;gap:8px;}
.alarm-list-head{padding:0 10px;border:1px solid #194966;background:#0b1d2e;color:#c8d7e8;font-size:12px;font-weight:750;}
.alarm-list{min-height:0;overflow-y:auto;overflow-x:hidden;}
.alarm-row{min-height:38px;padding:7px 10px;border-bottom:1px solid #132f44;background:#07131f;}
.alarm-time,.alarm-area,.alarm-msg,.alarm-val{font-size:13px;color:#d7e1ed;}.alarm-time{font-family:"Cascadia Mono",Consolas,monospace}.alarm-msg{color:#eef4fb}
.alarm-badge{justify-self:start;min-width:76px;padding:5px 7px;border:1px solid;border-radius:12px;text-align:center;font-size:11px;font-weight:800;}
.alarm-badge.critical{color:#ff7a7e;border-color:#a53a40;background:#2b1518}.alarm-badge.warning{color:#efb542;border-color:#9a6b19;background:#241b0e}.alarm-badge.info{color:#6fc6ff;border-color:#2779a8;background:#0c2638}
.alarm-list>div:only-child{display:flex;align-items:center;justify-content:center;min-height:74px;color:#55da70!important;font-size:17px;font-weight:750;}
.main-status-footer{min-height:36px;padding:0 16px;border:1px solid var(--line);border-radius:7px;background:#06131f;}
.main-status-footer .footer-label{padding-right:14px;border-right:1px solid #173d58;color:#f2f7fd;font-weight:750;}
.disabled-card{opacity:.5;filter:saturate(.35);}
@media (max-width:1400px){
  .cpd-dashboard{height:100%;display:block;overflow-y:auto;}
  .cpd-header{margin-bottom:8px}
  .cpd-main-grid{height:auto;grid-template-columns:1fr;overflow:visible}.cpd-col-left,.cpd-col-right{display:flex;flex-direction:column;gap:8px;overflow:visible}.cpd-card{min-height:190px}
  #bulkCard{min-height:300px}.cpd-col-left>.cpd-card:nth-child(2){min-height:240px}.cpd-bottom-grid .cpd-card{min-height:190px}
  .caa-card{min-height:190px}.aux-systems-card{min-height:220px}.alarm-card{min-height:260px}.main-status-footer{margin-top:8px;min-height:42px;flex-wrap:wrap}
}
@media (max-width:900px){
  .cpd-bottom-grid{grid-template-columns:1fr;overflow:visible}
  .main-status-footer{gap:10px;font-size:12px}.aux-systems-body>.cpd-card{grid-template-columns:100px minmax(0,1fr)}
  #mixingGrid{gap:4px}#mixingGrid .tank-circle{width:56px;height:56px;min-width:56px;min-height:56px;font-size:18px}
}
@media (prefers-reduced-motion:reduce){.cpd-dashboard *{transition:none!important;scroll-behavior:auto!important}}
/* ================= MAIN USING MIXING VISUAL SYSTEM ================= */
.cpd-dashboard{
  --font-ui:"Segoe UI Variable Text","Segoe UI",system-ui,sans-serif;
  --font-display:"Segoe UI Variable Display","Segoe UI",system-ui,sans-serif;
  --font-mono:ui-monospace,SFMono-Regular,Menlo,Consolas,"Liberation Mono",monospace;
  --text-xs:.875rem;
  --text-sm:.9375rem;
  --text-md:1.0625rem;
  --text-compact-value:1.25rem;
  --text-lg:1.625rem;
  --text-xl:2.25rem;
  --mt-page-surface:oklch(14.5% .016 250);
  --mt-panel-surface-top:oklch(22.5% .032 250);
  --mt-panel-surface-bottom:oklch(18.5% .026 250);
  --mt-card-surface:oklch(20.5% .027 250);
  --mt-content-surface:oklch(17% .020 250);
  --mt-plot-surface:oklch(17.5% .021 250);
  --mt-card-border:rgba(125,196,255,.34);
  --mt-card-border-soft:rgba(88,166,255,.24);
  --mt-card-highlight:rgba(255,255,255,.06);
  --mt-cyan:#31c4ff;
  --mt-cyan-soft:rgba(49,196,255,.34);
  --mt-edge-blue:rgba(35,139,230,.48);
  --mt-text:#f4f8ff;
  --mt-muted:rgba(206,222,240,.78);
  --green:#22c55e;
  --red:#ff5c5c;
  --amber:#e8a62b;
  --grey:#9aa6b4;
  isolation:isolate;
  color:var(--mt-text);
  font-family:var(--font-ui);
  font-kerning:normal;
  font-optical-sizing:auto;
  -webkit-font-smoothing:antialiased;
  background:
    radial-gradient(circle at 18% 0%,rgba(20,109,205,.10),transparent 34%),
    linear-gradient(rgba(72,153,230,.025) 1px,transparent 1px),
    linear-gradient(90deg,rgba(72,153,230,.025) 1px,transparent 1px),
    var(--mt-page-surface);
  background-size:auto,32px 32px,32px 32px,auto;
}
.cpd-header,
.summary-kpi-card,
.cpd-card,
.aux-systems-card,
.main-status-footer{
  border-color:var(--mt-edge-blue);
  border-radius:14px;
  background:linear-gradient(180deg,var(--mt-panel-surface-top),var(--mt-panel-surface-bottom));
  box-shadow:0 12px 26px rgba(0,0,0,.42),inset 0 1px 0 var(--mt-card-highlight),inset 0 0 0 1px rgba(125,196,255,.035);
}
.summary-kpi-card,
.cpd-card,
.aux-systems-card{
  position:relative;
}
.summary-kpi-card::before,
.cpd-card::before,
.aux-systems-card::before{
  content:"";
  position:absolute;
  z-index:2;
  left:16px;right:16px;top:0;height:1px;
  background:linear-gradient(90deg,transparent,rgba(49,196,255,.72),transparent);
  opacity:.75;
  pointer-events:none;
}
.cpd-header{
  background:linear-gradient(180deg,var(--mt-panel-surface-top),var(--mt-panel-surface-bottom));
}
.cpd-title{
  font-family:var(--font-display);
  font-size:var(--text-lg);
  font-weight:700;
  line-height:1.15;
  letter-spacing:.04em;
  color:#fff;
}
.cpd-subtitle{
  border-color:var(--mt-card-border);
  background:var(--mt-card-surface);
  color:#e7f4ff;
  font-size:var(--text-xs);
  font-weight:600;
  line-height:1.3;
  letter-spacing:.055em;
}
.summary-kpi-card{
  background:linear-gradient(180deg,var(--mt-panel-surface-top),var(--mt-panel-surface-bottom));
}
.summary-kpi-card .kpi-label{
  color:var(--mt-muted);
  font-size:var(--text-xs);
  font-weight:600;
  line-height:1.3;
  letter-spacing:.055em;
}
.summary-kpi-card .kpi-value{
  font-family:var(--font-display);
  font-size:var(--text-xl);
  font-weight:700;
  line-height:1.1;
  letter-spacing:0;
}
.summary-kpi-card .kpi-unit{color:var(--mt-muted);font-size:var(--text-md);font-weight:600;}
.summary-kpi-card .kpi-track{background:rgba(157,179,204,.24);}
.summary-kpi-card .kpi-track::after{background:#22c55e;box-shadow:0 0 8px rgba(34,197,94,.20);}
.summary-available .kpi-track::after{background:var(--mt-cyan);box-shadow:0 0 8px rgba(49,196,255,.18);}
.summary-kpi-card .kpi-green{color:#22c55e!important;text-shadow:0 0 8px rgba(34,197,94,.18);}
.summary-kpi-card .kpi-grey{color:var(--mt-cyan)!important;text-shadow:0 0 8px rgba(49,196,255,.16);}
.cpd-card-header,
.aux-systems-title{
  position:relative;
  z-index:1;
  background:linear-gradient(180deg,#243248,#18253a);
  border-bottom-color:rgba(88,166,255,.34);
  box-shadow:inset 0 1px 0 rgba(255,255,255,.06),0 4px 12px rgba(0,0,0,.18);
  color:#f4f8ff;
  font-family:var(--font-display);
  font-size:var(--text-md);
  font-weight:700;
  line-height:1.2;
  letter-spacing:.04em;
}
.cpd-card-body{color:var(--mt-text);}
.tank-circle{
  border-color:var(--mt-card-border-soft);
  border-radius:8px;
  background:var(--mt-content-surface);
  color:#eef6ff;
  font-family:var(--font-ui);
  font-size:var(--text-sm);
  font-weight:700;
  line-height:1.05;
  box-shadow:inset 0 1px 0 rgba(255,255,255,.04);
}
.tank-circle.green{
  border-color:rgba(0,255,120,.62);
  background:linear-gradient(135deg,rgba(0,255,120,.18) 0%,rgba(0,255,120,.07) 24%,rgba(4,18,14,.94) 100%);
  color:#dfffea;
  box-shadow:0 0 12px rgba(0,255,120,.26),0 0 24px rgba(0,255,120,.10),inset 0 0 0 1px rgba(0,255,120,.14),inset 0 0 20px rgba(0,255,120,.10);
}
.tank-circle.red{
  border-color:rgba(255,92,92,.55);
  background:linear-gradient(135deg,rgba(255,92,92,.16),rgba(35,10,14,.94));
  color:#ffe7e7;
  box-shadow:inset 0 0 20px rgba(255,92,92,.07);
}
.tank-circle.grey{
  border-color:rgba(160,170,185,.32);
  background:linear-gradient(180deg,oklch(25% .008 250),oklch(20% .008 250));
  color:#d5dce5;
  box-shadow:none;
}
.tank-circle[href]:hover{
  border-color:rgba(49,196,255,.70);
  box-shadow:0 0 0 1px rgba(49,196,255,.16),inset 0 1px 0 rgba(255,255,255,.05);
}
.mixing-row-labels span{
  border-color:var(--mt-edge-blue);
  border-radius:8px;
  background:var(--mt-card-surface);
  color:#dff5ff;
  font-family:var(--font-display);
  font-size:var(--text-md);
  font-weight:700;
  letter-spacing:.03em;
}
.main-status-footer{
  color:var(--mt-muted);
  font-size:var(--text-xs);
  font-weight:600;
  line-height:1.3;
  letter-spacing:.02em;
}
.legend-swatch{border-radius:4px;}
.state-green{border-color:rgba(0,255,120,.48);background:rgba(0,255,120,.16);}
.state-cyan{border-color:rgba(49,196,255,.58);background:rgba(49,196,255,.12);}
.state-grey{border-color:rgba(160,170,185,.42);background:oklch(24% .008 250);}
.state-amber{border-color:rgba(232,166,43,.64);background:rgba(232,166,43,.16);}
.state-red{border-color:rgba(255,92,92,.62);background:rgba(255,92,92,.16);}
.caa-unit-card{
  border-color:var(--mt-card-border-soft);
  border-radius:12px;
  background:var(--mt-card-surface);
  box-shadow:inset 0 1px 0 rgba(255,255,255,.04);
}
.caa-tank{
  border-bottom-color:rgba(125,196,255,.18);
  background:rgba(0,0,0,.12);
  color:#eef7ff;
  font-family:var(--font-display);
  font-size:var(--text-md);
  font-weight:700;
  letter-spacing:.04em;
}
.caa-label{
  color:var(--mt-muted);
  font-size:var(--text-xs);
  font-weight:600;
  letter-spacing:.055em;
}
.caa-value{
  color:#f4f8ff;
  font-size:var(--text-compact-value);
  font-weight:700;
}
.caa-unit-card:has(.caa-green){border-color:rgba(0,255,120,.38);background:linear-gradient(135deg,rgba(0,255,120,.12),var(--mt-card-surface) 58%);}
.caa-green{background:rgba(0,255,120,.08);color:#54e681;}
.caa-unit-card:has(.caa-grey){border-color:rgba(160,170,185,.28);background:linear-gradient(180deg,oklch(22% .008 250),oklch(18% .008 250));}
.caa-grey{background:rgba(255,255,255,.025);color:#d5dce5;}
.aux-systems-body{background:var(--mt-content-surface);}
