.tank-card-header{
  flex:0 0 64px;
  height:64px;
  padding:4px 12px;
  justify-content:space-between;
  gap:16px;
}
.tank-card-header>span{flex:0 0 auto;}
.tank-kpi-strip{
  flex:1 1 600px;
  width:100%;
  max-width:600px;
  height:100%;
  display:grid;
  grid-template-columns:repeat(3,minmax(0,1fr));
  gap:8px;
}
.tank-kpi-strip .summary-kpi-card{
  min-height:0;
  padding:4px 12px;
  display:flex;
  flex-direction:column;
  align-items:flex-end;
  justify-content:center;
  gap:4px;
  overflow:hidden;
  border:0;
  border-left:1px solid var(--mt-card-border-soft);
  border-radius:0;
  background:transparent;
  box-shadow:none;
}
.tank-kpi-strip .summary-kpi-card:first-child{border-left:0;}
.tank-kpi-strip .summary-kpi-card::before{display:none;}
.tank-kpi-strip .summary-kpi-card .kpi-label{
  color:var(--mt-muted);
  font-size:14px;
  font-weight:600;
  line-height:1.1;
  letter-spacing:.02em;
  white-space:nowrap;
}
.tank-kpi-strip .kpi-value-line{
  display:flex;
  align-items:baseline;
  justify-content:flex-end;
  gap:4px;
}
.tank-kpi-strip .summary-kpi-card .kpi-value{
  font-size:26px;
  line-height:1;
}
.tank-kpi-strip .summary-kpi-card .kpi-unit{
  font-size:14px;
  line-height:1;
}
.tank-kpi-strip .kpi-track{display:none;}
@media (max-width:900px){
  .tank-card-header{
    height:auto;
