function pad2(num) {
  return String(num).padStart(2, "0");
}

function makeCircle(labelTop, labelBottom, colorClass = "green", href = null, extraClass = "") {
  // Only tanks without a detailed-dashboard destination are disabled.
  if (!href) {
    return `<div class="tank-circle grey ${extraClass}">${labelTop}<br>${labelBottom}</div>`;
  }

  return `<a class="tank-circle ${colorClass} tank-link ${extraClass}" href="${href}" target="_self">${labelTop}<br>${labelBottom}</a>`;
}

