function renderBulk(disabled = false) {
  const bulkGrid = htmlNode.getElementById("bulkGrid");
  const bulkAvailability = htmlNode.getElementById("bulkAvailability");
  const bulkFilled = htmlNode.getElementById("bulkFilled");
  const bulkPercentage = htmlNode.getElementById("bulkPercentage");

  if (disabled) {
    setCardDisabled("bulkCard");
  } else {
    setCardEnabled("bulkCard");
  }

  let html = "";
  const tankStatusMap = {};

  // ===============================
  // QUERY A: bulk_tank_status
  // ===============================
  const bulkStatusSeries = data.series.find(s =>
    s.fields.some(f => f.name === "btNo") &&
    s.fields.some(f => f.name === "status")
  );

  if (bulkStatusSeries) {
    const btField = bulkStatusSeries.fields.find(f => f.name === "btNo");
    const statusField = bulkStatusSeries.fields.find(f => f.name === "status");

    if (btField && statusField) {
      for (let i = 0; i < btField.values.length; i++) {
        const btNo = String(btField.values.get(i));
        const status = Number(statusField.values.get(i));
        tankStatusMap[btNo] = status;
      }
    }
  }

  // ===============================
  // DRAW BULK TANKS
  // no data -> grey
  // status 1 -> green
  // status 0 -> grey
  // ===============================
  for (let i = cfg.bulkStart; i <= cfg.bulkEnd; i++) {
    const btNo = "BT" + pad2(i);
    let color = "grey";

    if (disabled) {
      color = "grey";
    } else if (tankStatusMap.hasOwnProperty(btNo)) {
      color = Number(tankStatusMap[btNo]) === 1 ? "green" : "grey";
    } else {
      color = "grey"; // no data = grey
    }

    const href = disabled
      ? null
      : `/foresight/d/${bulkTankUID}/all-plants-bulk-tank?orgId=1&from=now-6h&to=now&timezone=browser&var-plantNo=${plantNo}&var-tankNo=${btNo}`;

    html += makeCircle("BT", pad2(i), color, href);
  }

  bulkGrid.innerHTML = html;

  // ===============================
  // QUERY B: bulk_tank_summary
  // ===============================
  let filledCount = 0;
  let availabilityCount = 0;
  const totalBulkTanks = cfg.bulkEnd - cfg.bulkStart + 1;

  for (let i = cfg.bulkStart; i <= cfg.bulkEnd; i++) {
    const btNo = "BT" + pad2(i);

    if (tankStatusMap.hasOwnProperty(btNo) && Number(tankStatusMap[btNo]) === 1) {
      filledCount++;
    } else {
      availabilityCount++;
    }
  }

  const percentage = totalBulkTanks > 0
    ? Math.round((filledCount / totalBulkTanks) * 100)
    : 0;

  if (disabled) {
    if (bulkAvailability) bulkAvailability.textContent = "--";
    if (bulkFilled) bulkFilled.textContent = "--";
    if (bulkPercentage) bulkPercentage.textContent = "--";
  } else {
    if (bulkAvailability) bulkAvailability.textContent = availabilityCount;
    if (bulkFilled) bulkFilled.textContent = filledCount;
    if (bulkPercentage) bulkPercentage.textContent = percentage;
  }



}

function renderMixing(disabled = false) {
  const mixingGrid = htmlNode.getElementById("mixingGrid");
  const mixA = htmlNode.getElementById("mixA");
  const mixB = htmlNode.getElementById("mixB");
  const mixC = htmlNode.getElementById("mixC");

  const suffixes = ["A", "B", "C"];
  let html = "";

  const statusMap = {};
  let filledCount = 0;
  let availabilityCount = 0;

  const mixSeries = data.series.find(s =>
    s.fields.some(f => f.name === "mtNo") &&
    s.fields.some(f => f.name === "statusCode")
  );

  if (mixSeries) {
    const mtField = mixSeries.fields.find(f => f.name === "mtNo");
    const statusField = mixSeries.fields.find(f => f.name === "statusCode");

    if (mtField && statusField) {
      for (let idx = 0; idx < mtField.values.length; idx++) {
        statusMap[String(mtField.values.get(idx))] = Number(statusField.values.get(idx));
      }
    }
  }

  const mixCount = cfg.mixEnd - cfg.mixStart + 1;
  const totalCols = 12;

  suffixes.forEach(suffix => {
    for (let i = cfg.mixStart; i <= cfg.mixEnd; i++) {
      const padded = i < 100 ? String(i).padStart(2, "0") : String(i);
      const mtNo = `${padded}${suffix}`;
      //const mtNo = `${i < 100 ? String(i).padStart(2, "0") : i}${suffix}`;
      //console.log(padded)

      const href = disabled
        ? null
        : `/foresight/d/${mixTankUID}/all-plant-mixing-tank?orgId=1&from=now-6h&to=now&timezone=browser&var-tankNo=${padded}&var-tankSuffix=${suffix}&refresh=2h&var-plantNo=${plantNo}`;

/*for (let i = cfg.mixStart; i <= cfg.mixEnd; i++) {
  const padded = i < 100 ? String(i).padStart(2, "0") : String(i);
  const mtNo = `${padded}${suffix}`;

  const href = disabled
    ? null
    : `/d/${mixTankUID}/all-plant-mixing-tank?orgId=1&from=now-6h&to=now&timezone=browser&var-tankNo=${padded}&var-tankSuffix=${suffix}&refresh=2h&var-plantNo=${plantNo}`;
}*/
      let color = "grey";
      const statusCode = statusMap[mtNo];

      if (disabled) {
        color = "grey";
      } else if (statusCode === 2) {
        color = "red";
      } else if (statusCode === 1) {
        color = "green";
      } else {
        color = "grey";
      }

      // Green and red tanks are occupied; grey tanks are available / empty.
      if (color === "grey") {
        availabilityCount++;
      } else {
        filledCount++;
      }

      html += makeCircle("MT", `${padded}${suffix}`, color, href);
    }

    // NA placeholders should NOT be counted as available
    if (mixCount < totalCols) {
      for (let j = 0; j < totalCols - mixCount; j++) {
        html += `<div class="tank-circle grey">NA<br></div>`;
      }
    }
  });

  mixingGrid.innerHTML = html;

  const totalMixingTanks = mixCount * suffixes.length;
  const utilization = totalMixingTanks > 0
    ? Math.round((filledCount / totalMixingTanks) * 100)
    : 0;

  if (disabled) {
    if (mixA) mixA.textContent = "--";
    if (mixB) mixB.textContent = "--";
    if (mixC) mixC.textContent = "--";
  } else {
    if (mixA) mixA.textContent = filledCount;
    if (mixB) mixB.textContent = availabilityCount;
    if (mixC) mixC.textContent = utilization;
  }
}

function renderCoagulant(disabled = false) {
  const coagulantGrid = htmlNode.getElementById("coagulantGrid");
  let html = "";

  const statusMap = {};

  // Query D -> coagulant status
  const coagSeries = data.series.find(s =>
    s.fields.some(f => f.name === "ctNo") &&
    s.fields.some(f => f.name === "status")
  );

  if (coagSeries) {
    const ctField = coagSeries.fields.find(f => f.name === "ctNo");
    const statusField = coagSeries.fields.find(f => f.name === "status");

    if (ctField && statusField) {
      for (let idx = 0; idx < ctField.values.length; idx++) {
        const ctNo = String(ctField.values.get(idx)).toUpperCase().trim();
        const status = Number(statusField.values.get(idx));
        statusMap[ctNo] = status;
      }
    }
  }

  ["A", "B"].forEach(suffix => {
    for (let i = 1; i <= 5; i++) {
      const ctNo = `CT${i}${suffix}`;

      let color = "grey";

      if (disabled) {
        color = "grey";
      } else if (statusMap.hasOwnProperty(ctNo)) {
        const status = statusMap[ctNo];
        if (status === 2) {
          color = "red";
        } else if (status === 1) {
          color = "green";
        } else {
          color = "grey";
        }
      } else {
        color = "grey"; // no data
      }

      const href = disabled
        ? null
        : `/foresight/d/${coagTankUID}/all-plant-coagulant-tank?orgId=1&from=now-6h&to=now&timezone=browser&var-plantNo=${plantNo}&var-tankNo=${i}&var-tankSuffix=${suffix}`;

      html += makeCircle("CT", `${i}${suffix}`, color, href);
    }
  });

  coagulantGrid.innerHTML = html;
}

