function renderCAA() {
  const acidSeries = data.series.find(s => String(s.refId).toUpperCase() === "E");
  const alkSeries = data.series.find(s => String(s.refId).toUpperCase() === "F");

  const acid1Tank = htmlNode.getElementById("caaTankAcid1");
  const acid2Tank = htmlNode.getElementById("caaTankAcid2");
  const alk1Tank = htmlNode.getElementById("caaTankAlk1");
  const alk2Tank = htmlNode.getElementById("caaTankAlk2");

  const acid1Panel = htmlNode.getElementById("caaPanelAcid1");
  const acid2Panel = htmlNode.getElementById("caaPanelAcid2");
  const alk1Panel = htmlNode.getElementById("caaPanelAlk1");
  const alk2Panel = htmlNode.getElementById("caaPanelAlk2");

  const acid1Strength = htmlNode.getElementById("caaAcid1Strength");
  const acid2Strength = htmlNode.getElementById("caaAcid2Strength");
  const acid1Status = htmlNode.getElementById("caaAcid1Status");
  const acid2Status = htmlNode.getElementById("caaAcid2Status");

  const alk1Strength = htmlNode.getElementById("caaAlk1Strength");
  const alk2Strength = htmlNode.getElementById("caaAlk2Strength");
  const alk1Status = htmlNode.getElementById("caaAlk1Status");
  const alk2Status = htmlNode.getElementById("caaAlk2Status");

  const caaUrl = `/foresight/d/${caaTankUID}/caa-dashboard?orgId=1&from=now-3h&to=now&timezone=browser&var-plantNo=${plantNo}`;

  [acid1Tank, acid2Tank, alk1Tank, alk2Tank].forEach(el => {
    if (el) {
      el.setAttribute("href", caaUrl);
      el.setAttribute("target", "_self");
    }
  });

  function resetCAABox(tankEl, panelEl, valueEl, statusEl) {
    if (tankEl) {
      tankEl.classList.remove("caa-green");
      tankEl.classList.add("caa-grey");
    }
    if (panelEl) {
      panelEl.classList.remove("caa-panel-green");
      panelEl.classList.add("caa-panel-grey");
    }
    if (valueEl) valueEl.textContent = "-- %";
    if (statusEl) statusEl.textContent = "--";
  }

  function activateCAABox(tankEl, panelEl) {
    if (tankEl) {
      tankEl.classList.remove("caa-grey");
      tankEl.classList.add("caa-green");
    }
    if (panelEl) {
      panelEl.classList.remove("caa-panel-grey");
      panelEl.classList.add("caa-panel-green");
    }
  }

  resetCAABox(acid1Tank, acid1Panel, acid1Strength, acid1Status);
  resetCAABox(acid2Tank, acid2Panel, acid2Strength, acid2Status);
  resetCAABox(alk1Tank, alk1Panel, alk1Strength, alk1Status);
  resetCAABox(alk2Tank, alk2Panel, alk2Strength, alk2Status);

  if (acidSeries) {
    const tankField = acidSeries.fields.find(f => f.name === "tankNo");
    const acidField = acidSeries.fields.find(f => f.name === "acid_current");
    const statusField = acidSeries.fields.find(f => f.name === "status");

    if (tankField && acidField && statusField) {
      for (let i = 0; i < tankField.values.length; i++) {
        const tankNo = String(tankField.values.get(i) || "").toUpperCase();
        const acidVal = Number(acidField.values.get(i));
        const statusVal = Number(statusField.values.get(i));

        if (tankNo === "1") {
          if (acid1Strength) acid1Strength.textContent = Number.isFinite(acidVal) ? acidVal.toFixed(2) + " %" : "-- %";
          if (acid1Status) acid1Status.textContent = statusVal === 2 ? "OUT OF SPEC" : statusVal === 1 ? "OK" : "--";
          if (statusVal === 1 || statusVal === 2) activateCAABox(acid1Tank, acid1Panel);
        }

        if (tankNo === "2") {
          if (acid2Strength) acid2Strength.textContent = Number.isFinite(acidVal) ? acidVal.toFixed(2) + " %" : "-- %";
          if (acid2Status) acid2Status.textContent = statusVal === 2 ? "OUT OF SPEC" : statusVal === 1 ? "OK" : "--";
          if (statusVal === 1 || statusVal === 2) activateCAABox(acid2Tank, acid2Panel);
        }
      }
    }
  }

  if (alkSeries) {
    const tankField = alkSeries.fields.find(f => f.name === "tankNo");
    const alkField = alkSeries.fields.find(f => f.name === "alkaline_current");
    const statusField = alkSeries.fields.find(f => f.name === "status");

    if (tankField && alkField && statusField) {
      for (let i = 0; i < tankField.values.length; i++) {
        const tankNo = String(tankField.values.get(i) || "").toUpperCase();
        const alkVal = Number(alkField.values.get(i));
        const statusVal = Number(statusField.values.get(i));

        if (tankNo === "1") {
          if (alk1Strength) alk1Strength.textContent = Number.isFinite(alkVal) ? alkVal.toFixed(2) + " %" : "-- %";
          if (alk1Status) alk1Status.textContent = statusVal === 2 ? "OUT OF SPEC" : statusVal === 1 ? "OK" : "--";
          if (statusVal === 1 || statusVal === 2) activateCAABox(alk1Tank, alk1Panel);
        }

        if (tankNo === "2") {
          if (alk2Strength) alk2Strength.textContent = Number.isFinite(alkVal) ? alkVal.toFixed(2) + " %" : "-- %";
          if (alk2Status) alk2Status.textContent = statusVal === 2 ? "OUT OF SPEC" : statusVal === 1 ? "OK" : "--";
          if (statusVal === 1 || statusVal === 2) activateCAABox(alk2Tank, alk2Panel);
        }
      }
    }
  }
}



