function renderRealAlarms() {
  const alarmList = htmlNode.querySelector(".alarm-list");
  const alarmVals = htmlNode.querySelectorAll(".alarm-kpi-val");

  let critical = 0;
  let warning = 0;
  let rows = "";

  function getAlarmTime(series, i) {
    const sourceField = series.fields.find(f => f.name === "source_time");

    if (sourceField) {
      const sourceMs = Number(sourceField.values.get(i));
      if (Number.isFinite(sourceMs) && sourceMs > 0) {
        const d = new Date(sourceMs);
        return d.toLocaleTimeString([], {
          hour: "2-digit",
          minute: "2-digit"
        });
      }
    }

    const timeField =
      series.fields.find(f => f.name === "time") ||
      series.fields.find(f => f.type === "time");

    if (!timeField) return "--";

    const rawTime = timeField.values.get(i);
    const d = new Date(rawTime);

    if (isNaN(d.getTime())) return "--";

    return d.toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit"
    });
  }

  function addAlarm(area, tank, message, value, severity, alarmTime) {
    const now = alarmTime || "--";

    if (severity === "CRITICAL") critical++;
    if (severity === "WARNING") warning++;

    rows += `
      <div class="alarm-row">
        <div class="alarm-time">${now}</div>
        <div class="alarm-area">${area}</div>
        <div class="alarm-msg">${tank} – ${message}</div>
        <div class="alarm-val">${value}</div>
        <div class="alarm-badge ${severity === "CRITICAL" ? "critical" : "warning"}">${severity}</div>
      </div>
    `;
  }

  // Mixing tank alarms from statusCode
  const mixSeries = data.series.find(s =>
    s.fields.some(f => f.name === "mtNo") &&
    s.fields.some(f => f.name === "statusCode")
  );

  if (mixSeries) {
    const mtField = mixSeries.fields.find(f => f.name === "mtNo");
    const statusField = mixSeries.fields.find(f => f.name === "statusCode");

    for (let i = 0; i < mtField.values.length; i++) {
      const mtNo = String(mtField.values.get(i));
      const status = Number(statusField.values.get(i));

      if (status === 2) {
        addAlarm("MIXING", `MT ${mtNo}`, "Quality out of spec", "OOS", "CRITICAL", getAlarmTime(mixSeries, i));
      }
    }
  }

  // Coagulant alarms from status
  const coagSeries = data.series.find(s =>
    s.fields.some(f => f.name === "ctNo") &&
    s.fields.some(f => f.name === "status")
  );

  if (coagSeries) {
    const ctField = coagSeries.fields.find(f => f.name === "ctNo");
    const statusField = coagSeries.fields.find(f => f.name === "status");

    for (let i = 0; i < ctField.values.length; i++) {
      const ctNo = String(ctField.values.get(i));
      const status = Number(statusField.values.get(i));

      if (status === 2) {
        addAlarm("COAGULANT", ctNo, "CN / MRA / pH out of spec", "OOS", "CRITICAL", getAlarmTime(coagSeries, i));
      }
    }
  }

  // CAA alarms from status
  ["E", "F"].forEach(refId => {
    const caaSeries = data.series.find(s => String(s.refId).toUpperCase() === refId);
    if (!caaSeries) return;

    const tankField = caaSeries.fields.find(f => f.name === "tankNo");
    const statusField = caaSeries.fields.find(f => f.name === "status");

    if (!tankField || !statusField) return;

    for (let i = 0; i < tankField.values.length; i++) {
      const tankNo = String(tankField.values.get(i));
      const status = Number(statusField.values.get(i));

      if (status === 2) {
        addAlarm("CAA", tankNo, "Strength out of spec", "OOS", "CRITICAL", getAlarmTime(caaSeries, i));
      }
    }
  });

  if (alarmVals[0]) alarmVals[0].textContent = critical + warning;

  if (alarmList) {
    alarmList.innerHTML = rows || `
      <div style="text-align:center; padding:20px; color:#d5dbe3;">
        No active alarms
      </div>
    `;
  }
}

